async function loadData() {
  try { const raw = localStorage.getItem(KEY); if (raw) return JSON.parse(raw); } catch (e) {}
  const s = seed();
  try { localStorage.setItem(KEY, JSON.stringify(s)); } catch (e) {}
  return s;
}

