/* Searchable student selector — matters once a center has 50+ students,
   where a plain <select> becomes painful to scroll through. Filters by
   name OR batch as you type, e.g. "arya" or "SSC-10" both work. */
function StudentPicker({ ids, students, value, onChange, getExtra, style, dark }) {
  const [open, setOpen] = useState(false);
  const [q, setQ] = useState("");
  const wrapRef = useRef(null);
  const selected = students[value];

  useEffect(() => {
    const onClick = (e) => { if (wrapRef.current && !wrapRef.current.contains(e.target)) { setOpen(false); setQ(""); } };
    document.addEventListener("mousedown", onClick);
    return () => document.removeEventListener("mousedown", onClick);
  }, []);

  const filtered = useMemo(() => {
    const needle = q.trim().toLowerCase();
    if (!needle) return ids;
    return ids.filter((id) => {
      const s = students[id];
      return (s.name + " " + s.batch).toLowerCase().includes(needle);
    });
  }, [ids, students, q]);

  const inputStyle = {
    padding: "8px 10px", borderRadius: 8, fontWeight: 700, fontFamily: "'Karla',sans-serif",
    width: "100%", outline: "none",
    border: dark ? "none" : "1.5px solid #DDE2EA",
    background: dark ? "#fff" : "#fff", color: "#13294B",
  };

  return (
    <div ref={wrapRef} style={{ position: "relative", ...style }}>
      <input
        value={open ? q : (selected ? `${selected.name} — ${selected.batch}` : "")}
        onFocus={() => { setOpen(true); setQ(""); }}
        onChange={(e) => setQ(e.target.value)}
        placeholder="Search name or batch…"
        style={inputStyle}
      />
      {open && (
        <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0, maxHeight: 280, overflowY: "auto", background: "#fff", border: "1.5px solid #DDE2EA", borderRadius: 10, boxShadow: "0 12px 28px rgba(0,0,0,0.14)", zIndex: 60, color: "#13294B" }}>
          {filtered.length === 0 && <div style={{ padding: "12px", fontSize: 13, color: "#7A8794" }}>No students match "{q}".</div>}
          {filtered.slice(0, 60).map((id) => (
            <div key={id} onMouseDown={() => { onChange(id); setOpen(false); setQ(""); }}
              style={{ padding: "9px 12px", cursor: "pointer", fontSize: 14, display: "flex", justifyContent: "space-between", gap: 8, background: id === value ? "#EDF1FA" : "transparent", color: "#13294B" }}>
              <span>{students[id].name} <span style={{ color: "#7A8794", fontSize: 12 }}>— {students[id].batch}</span></span>
              {getExtra && <span style={{ color: "#7A8794", fontSize: 12 }}>{getExtra(id)}</span>}
            </div>
          ))}
          {filtered.length > 60 && <div style={{ padding: "8px 12px", fontSize: 12, color: "#7A8794", borderTop: "1px solid #F0F2F5" }}>+{filtered.length - 60} more — keep typing to narrow it down</div>}
        </div>
      )}
    </div>
  );
}
